import React from 'react';

const skillsData = [
  {
    name: 'HTML & CSS',
    level: 85,
    description: 'Experienced in building responsive layouts and modern UI designs.',
  },
  {
    name: 'JavaScript',
    level: 70,
    description: 'Strong understanding of core JS concepts and DOM manipulation.',
  },
  {
    name: 'React',
    level: 60,
    description: 'Able to build component-based applications with hooks.',
  },
];

const Skills = () => (
  <section
    id="Skills"
    className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
    style={{
      background: '#000',
      fontFamily: "'Orbitron', sans-serif",
    }}
  >
    <h1 className="font-bold text-4xl text-white text-center mb-12">
      Skills
    </h1>

    <div className="w-full max-w-2xl flex flex-col gap-5">
      {skillsData.map((skill, i) => (
        <div
          key={i}
          className="rounded-xl p-6 shadow-md"
          style={{
            background: '#fff', // ✅ WHITE CONTAINER
            borderLeft: '5px solid #0d6efd',
          }}
        >
          <h3 className="font-bold text-lg text-black">
            {skill.name}
          </h3>

          <p className="text-sm mt-2 text-gray-700">
            {skill.description}
          </p>

          <p className="text-sm mt-2 text-gray-500">
            Proficiency: {skill.level}%
          </p>
        </div>
      ))}
    </div>
  </section>
);

export default Skills;
